noncompliant:
void function() {
  int x = 10;
  {
    int y = 20; // Noncompliant: unnecessary nested block
    printf("%d", y);
  }
}

void complex_function() {
  int a = 1;
  {
    // Noncompliant: nested block suggests function is too complex
    int b = 2;
    {
      int c = 3;
      printf("%d", c);
    }
  }
}

compliant:
void function() {
  int x = 10;
  int y = 20; // Compliant: no unnecessary nesting
  printf("%d", y);
}

void switch_example(int value) {
  switch(value) {
    case 1: {
      // Compliant: nested block in switch case is acceptable
      int local_var = 100;
      printf("%d", local_var);
      break;
    }
    default:
      break;
  }
}
